import './settings-menu.css';
import './lights.css';
import Easca from '../easca/easca2';
import bg0 from '../../images/fog3.png';
import eye1 from '../../images/gifs/suile0.gif';
import eye2 from '../../images/gifs/suile3.gif';
import React, { useEffect,useState  } from 'react';
import ironkey from '../../images/iron-key.png';
import keyface from '../../images/gifs/keyface.gif';
import greyBG from '../../images/cut-scenes/rectanglesbg0.jpg';
import lordIronkey from '../../images/gifs/keyface.gif'
import ReactAudioPlayer from 'react-audio-player';
import settingsBtnKeyboard from '../../images/settings/keyboard.png';
import distantHills from '../../images/newbg4town.png';
import blurryBG from '../../images/newbg2.png';
import History from '../history/history'
import  Rings6 from '../Rings/Rings6';
let lyricID = 0;



    useEffect(() => {
        // Define the Phaser 3 game configuration
        const config = {
            type: Phaser.AUTO,
            width: 800,
            height: 600,
            scene: {
                preload: preload,
                create: create
            }
        };

        // Create a new Phaser 3 game instance
        const game = new Phaser.Game(config);

        // Function to load assets
        function preload() {
            this.load.image('lordIronkey', lordIronkey);
        }

        // Function to create the scene
        function create() {
            // Add the lordIronkey sprite
            this.add.sprite(400, 300, 'lordIronkey');
        }

        // Clean up function to destroy the game instance when the component unmounts
        return () => {
            game.destroy(true);
        };
    }, []);

    // Autoplay the music on component mount
    useEffect(() => {
        const audioPlayer = new Audio(saveTheCity);
        audioPlayer.play();
        return () => {
            audioPlayer.pause();
        };
    }, []);

    // Handle about button click
    const handleAboutClick = () => {
        setShowHist(true);
        enterFullscreen();
    };

    // Handle begin button click
    const handleBeginClick = () => {
        props.handleInputSelect('begin');
        enterFullscreen();
    };

    const [showHistory, setShowHist] = useState(false);
    let toggleIsOn = props.toggleIsOn;
    let isOn = props.isOn;



